Email_Body.inputs:
@replace(
  replace(
    replace(
      replace(
        replace(
          replace(
            replace(
              body('Parse_JSON')?['value'][0]?['EN_Body'],
              '[date]', triggerBody()?['DateTimestamp']
            ),
            '[User]', triggerBody()?['CurrentUser']
          ),
          '[template name]', triggerBody()?['FormName']
        ),
        '[HRC]', variables('sessionLink')
      ),
      '[group]', variables('Groupname')
    ),
    '[ReviewerType]', triggerBody()?['ReviewerType']
  ),
  '[BudgetSection]', triggerBody()?['BudgetSection']
)

